import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";
import Card from "../components/Card";
import CardData from "../components/CardData";
import top from "../assets/Result/top.png";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const { gem_prediction, shape_prediction, image } = location.state || {};

  return (
    <>
      <Topnav />

      {/* Header */}
      <div className="relative flex flex-col items-center">
   

      

        <p className="mt-24 text-3xl font-bold text-gray-900 text-center">
          Gem Analysis Results
        </p>
      </div>

      {/* Main Content */}
      <div className="max-w-6xl mx-auto px-6 py-12 space-y-12">

        {/* Result Card */}
        <div className="flex flex-col items-center gap-6">
          <Card
            title={gem_prediction}
            description={shape_prediction}
            imageUrl={image ? URL.createObjectURL(image) : ""}
          />
          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-4 w-40 py-2.5 px-5 text-white bg-blue-800 rounded-full border border-gray-200 hover:bg-blue-700 hover:text-white transition duration-300 focus:outline-none focus:ring-4 focus:ring-blue-300"
          >
            Re-Analyze
          </button>
        </div>

      
      </div>

      <Footer />
    </>
  );
}

export default Result;
